raw_html:
/*
You can add your own CSS here.

Click the help icon above to learn more.
*/

#menu-item-480 { 
background-color: #3988ff;
border-radius:5px;
}

#pagetitle {
	display: none;
}

.page #content {
padding-top: 0px !important;
}

a:link, a:visited {
	color:#1203FA;
	text-decoration: ;
}

a:hover {
	color: #ABA6FA;
}

.customize-partial-edit-shortcut-button {
	border: none;
}

li.email {
background-image: url('https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRyaxr8q588-a3vEWFRpO_UqsojFqHSzP5WO-FEr2gLaNMpgFXhng');
background-repeat: no-repeat;
background-position: left center;
list-style: none;
background-size: 30px;
padding: 20px 0px 20px 45px;
}

li.phone{
background-image: url('https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRCxmMJPT4xOdWfVt-rtiuVD0mK5qpNxho-e05Geb8yKACTv5Mwbg');
background-repeat: no-repeat;
background-position: left center;
list-style: none;
background-size: 40px;
padding: 20px 0px 20px 45px;
}

.wp-block-image figcaption {
	text-align: center;
	font-size: 14px;
	padding: 15px;
	color: #888;
}

/* Add the text * "my-justify-class" to 
 * the Additional CSS class field of
 * a text paragraph to justify align 
 * the text in that paragraph
 */
@media only screen and (min-width: 1280px) {
    p.my-justify-class {     
	  text-align: justify; 
	}
}

